84: const Http::HeaderEntry* HeaderFormatter::findHeader(const Http::HeaderMap& headers) const {
85:   const auto header = headers.get(main_header_);
86: 
87:   if (header.empty() && !alternative_header_.get().empty()) {
88:     const auto alternate_header = headers.get(alternative_header_);
89:     // TODO(https://github.com/envoyproxy/envoy/issues/13454): Potentially log all header values.
90:     return alternate_header.empty() ? nullptr : alternate_header[0];
91:   }
92: 
93:   return header.empty() ? nullptr : header[0];
94: }
