96: absl::optional<std::string> HeaderFormatter::format(const Http::HeaderMap& headers) const {
97:   const Http::HeaderEntry* header = findHeader(headers);
98:   if (!header) {
99:     return absl::nullopt;
100:   }
101: 
102:   absl::string_view val = header->value().getStringView();
103:   val = SubstitutionFormatUtils::truncateStringView(val, max_length_);
104:   return std::string(val);
105: }
