240: absl::optional<std::string>
241: GrpcStatusFormatter::formatWithContext(const HttpFormatterContext& context,
242:                                        const StreamInfo::StreamInfo& info) const {
243:   if (Runtime::runtimeFeatureEnabled(
244:           "envoy.reloadable_features.validate_grpc_header_before_log_grpc_status")) {
245:     if (!Grpc::Common::isGrpcRequestHeaders(context.requestHeaders())) {
246:       return absl::nullopt;
247:     }
248:   }
249:   const auto grpc_status = Grpc::Common::getGrpcStatus(context.responseTrailers(),
250:                                                        context.responseHeaders(), info, true);
251:   if (!grpc_status.has_value()) {
252:     return absl::nullopt;
253:   }
254:   switch (format_) {
255:   case CamelString: {
256:     const auto grpc_status_message = Grpc::Utility::grpcStatusToString(grpc_status.value());
257:     if (grpc_status_message == EMPTY_STRING || grpc_status_message == "InvalidCode") {
258:       return std::to_string(grpc_status.value());
259:     }
260:     return grpc_status_message;
261:   }
262:   case SnakeString: {
263:     const auto grpc_status_message =
264:         absl::StatusCodeToString(static_cast<absl::StatusCode>(grpc_status.value()));
265:     if (grpc_status_message == EMPTY_STRING) {
266:       return std::to_string(grpc_status.value());
267:     }
268:     return grpc_status_message;
269:   }
270:   case Number: {
271:     return std::to_string(grpc_status.value());
272:   }
273:   }
274:   PANIC_DUE_TO_CORRUPT_ENUM;
275: }
