84: ProtobufWkt::Value
85: MetadataFormatter::formatMetadataValue(const envoy::config::core::v3::Metadata& metadata) const {
86:   if (path_.empty()) {
87:     const auto filter_it = metadata.filter_metadata().find(filter_namespace_);
88:     if (filter_it == metadata.filter_metadata().end()) {
89:       return SubstitutionFormatUtils::unspecifiedValue();
90:     }
91:     ProtobufWkt::Value output;
92:     output.mutable_struct_value()->CopyFrom(filter_it->second);
93:     return output;
94:   }
95: 
96:   const ProtobufWkt::Value& val =
97:       Config::Metadata::metadataValue(&metadata, filter_namespace_, path_);
98:   if (val.kind_case() == ProtobufWkt::Value::KindCase::KIND_NOT_SET) {
99:     return SubstitutionFormatUtils::unspecifiedValue();
100:   }
101: 
102:   return val;
103: }
