158: FilterStateFormatter::create(const std::string& format, const absl::optional<size_t>& max_length,
159:                              bool is_upstream) {
160:   std::string key, serialize_type, field_name;
161:   static constexpr absl::string_view PLAIN_SERIALIZATION{"PLAIN"};
162:   static constexpr absl::string_view TYPED_SERIALIZATION{"TYPED"};
163:   static constexpr absl::string_view FIELD_SERIALIZATION{"FIELD"};
164: 
165:   SubstitutionFormatUtils::parseSubcommand(format, ':', key, serialize_type, field_name);
166:   if (key.empty()) {
167:     throwEnvoyExceptionOrPanic("Invalid filter state configuration, key cannot be empty.");
168:   }
169: 
170:   if (serialize_type.empty()) {
171:     serialize_type = std::string(TYPED_SERIALIZATION);
172:   }
173:   if (serialize_type != PLAIN_SERIALIZATION && serialize_type != TYPED_SERIALIZATION &&
174:       serialize_type != FIELD_SERIALIZATION) {
175:     throwEnvoyExceptionOrPanic("Invalid filter state serialize type, only "
176:                                "support PLAIN/TYPED/FIELD.");
177:   }
178:   if ((serialize_type == FIELD_SERIALIZATION) ^ !field_name.empty()) {
179:     throwEnvoyExceptionOrPanic("Invalid filter state serialize type, FIELD "
180:                                "should be used with the field name.");
181:   }
182: 
183:   const bool serialize_as_string = serialize_type == PLAIN_SERIALIZATION;
184: 
185:   return std::make_unique<FilterStateFormatter>(key, max_length, serialize_as_string, is_upstream,
186:                                                 field_name);
187: }
