728:   std::string toString(const Network::Address::Instance& address) const {
729:     switch (extraction_type_) {
730:     case StreamInfoAddressFieldExtractionType::WithoutPort:
731:       return StreamInfo::Utility::formatDownstreamAddressNoPort(address);
732:     case StreamInfoAddressFieldExtractionType::JustPort:
733:       return StreamInfo::Utility::formatDownstreamAddressJustPort(address);
734:     case StreamInfoAddressFieldExtractionType::WithPort:
735:     default:
736:       return address.asString();
737:     }
738:   }
